package org.eclipse.rdf4j.query.algebra.evaluation.function;

import static org.assertj.core.api.Assertions.assertThat;

import java.lang.reflect.Method;
import java.util.Optional;

import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.algebra.FunctionCall;
import org.junit.jupiter.api.Test;

public class FunctionCharacteristicsTest {

	@Test
	public void exposesRicherExperimentalFunctionContract() throws Exception {
		Class<?> characteristics = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.function.FunctionCharacteristics");
		Class<?> provider = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.function.FunctionCharacteristicsProvider");

		assertThat(characteristics.isRecord()).isTrue();
		assertThat(provider.isInterface()).isTrue();
		assertThat(provider.getMethod("characteristics").getReturnType()).isEqualTo(characteristics);
		assertThat(characteristics.getRecordComponents()).extracting(component -> component.getName())
				.containsExactly("stability", "sideEffects", "invocationPartitioning", "rowIdentity",
						"failureBehavior");
	}

	@Test
	public void classifierHonorsRichLegacyAndFailClosedContracts() throws Exception {
		FunctionCharacteristics rich = FunctionCharacteristics.queryStable(
				FunctionCharacteristics.FailureBehavior.TOTAL_WHEN_ARGUMENTS_BOUND);
		assertThat(classify(new RichFunction("urn:test:rich", rich))).isEqualTo(rich);

		FunctionCharacteristics legacy = classify(new TestFunction("urn:test:legacy") {
			@Override
			public boolean mustReturnDifferentResult() {
				return true;
			}
		});
		assertThat(legacy.stability()).isEqualTo(FunctionCharacteristics.Stability.INVOCATION_SENSITIVE);
		assertThat(legacy.invocationPartitioning())
				.isEqualTo(FunctionCharacteristics.InvocationPartitioning.SENSITIVE);
		assertThat(legacy.sideEffects()).isEqualTo(FunctionCharacteristics.SideEffects.NONE);

		assertThat(classify(new TestFunction("urn:test:unknown")))
				.isEqualTo(FunctionCharacteristics.unknown());
	}

	private static FunctionCharacteristics classify(Function function) throws Exception {
		FunctionRegistry registry = FunctionRegistry.getInstance();
		Optional<Function> previous = registry.add(function);
		try {
			Class<?> classifier = Class.forName(
					"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope.FunctionCharacteristicsRegistry");
			Method method = classifier.getDeclaredMethod("classify", FunctionCall.class);
			method.setAccessible(true);
			return (FunctionCharacteristics) method.invoke(null, new FunctionCall(function.getURI()));
		} finally {
			registry.remove(function);
			previous.ifPresent(registry::add);
		}
	}

	private static class TestFunction implements Function {

		private final String uri;

		private TestFunction(String uri) {
			this.uri = uri;
		}

		@Override
		public String getURI() {
			return uri;
		}

		@Override
		@SuppressWarnings("deprecation")
		public Value evaluate(ValueFactory valueFactory, Value... args) {
			return valueFactory.createLiteral(uri);
		}
	}

	private static final class RichFunction extends TestFunction implements FunctionCharacteristicsProvider {

		private final FunctionCharacteristics characteristics;

		private RichFunction(String uri, FunctionCharacteristics characteristics) {
			super(uri);
			this.characteristics = characteristics;
		}

		@Override
		public FunctionCharacteristics characteristics() {
			return characteristics;
		}
	}
}
